  1→import { useState } from "react";
  2→import type { Race } from "../../lib/types";
  3→import EscEditBox from "../EscEditBox";
  4→import GlueDropdown from "../GlueDropdown";
  5→import GlueSmallButton from "../GlueSmallButton";
  6→import GlueBorderedButton from "../GlueBorderedButton";
  7→import { importBuilds } from "../../state/buildOrders";
  8→
  9→const RACES: Race[] = ["Human", "Orc", "NightElf", "Undead"];
 10→const RACE_LABELS: Record<Race, string> = {
 11→  Human: "Human",
 12→  Orc: "Orc",
 13→  NightElf: "Night Elf",
 14→  Undead: "Undead",
 15→};
 16→const DIFFICULTIES = ["Beginner", "Intermediate", "Advanced"] as const;
 17→type Difficulty = (typeof DIFFICULTIES)[number];
 18→
 19→interface StepRow {
 20→  time: string;
 21→  instruction: string;
 22→  food: string;
 23→}
 24→
 25→interface SkillRow {
 26→  level: string;
 27→  skill: string;
 28→  icon: string;
 29→}
 30→
 31→export default function BuildOrderInputSection() {
 32→  const [name, setName] = useState("");
 33→  const [race, setRace] = useState<Race>("Human");
 34→  const [vs, setVs] = useState("");
 35→  const [difficulty, setDifficulty] = useState<Difficulty>("Beginner");
 36→  const [description, setDescription] = useState("");
 37→  const [note, setNote] = useState("");
 38→  const [keyTimingMinute, setKeyTimingMinute] = useState("");
 39→  const [keyTimingNote, setKeyTimingNote] = useState("");
 40→  const [steps, setSteps] = useState<StepRow[]>([
 41→    { time: "0:00", instruction: "", food: "" },
 42→  ]);
 43→  const [skills, setSkills] = useState<SkillRow[]>([]);
 44→  const [status, setStatus] = useState("");
 45→
 46→  function updateStep(index: number, field: keyof StepRow, value: string) {
 47→    setSteps((prev) =>
 48→      prev.map((s, i) => (i === index ? { ...s, [field]: value } : s)),
 49→    );
 50→  }
 51→
 52→  function addStep() {
 53→    setSteps((prev) => [...prev, { time: "", instruction: "", food: "" }]);
 54→  }
 55→
 56→  function removeStep(index: number) {
 57→    setSteps((prev) => prev.filter((_, i) => i !== index));
 58→  }
 59→
 60→  function updateSkill(index: number, field: keyof SkillRow, value: string) {
 61→    setSkills((prev) =>
 62→      prev.map((s, i) => (i === index ? { ...s, [field]: value } : s)),
 63→    );
 64→  }
 65→
 66→  function addSkill() {
 67→    setSkills((prev) => [
 68→      ...prev,
 69→      { level: String(prev.length + 1), skill: "", icon: "" },
 70→    ]);
 71→  }
 72→
 73→  function removeSkill(index: number) {
 74→    setSkills((prev) => prev.filter((_, i) => i !== index));
 75→  }
 76→
 77→  function handleSubmit() {
 78→    const keyTimingMin = Number(keyTimingMinute);
 79→    const build = {
 80→      name,
 81→      race,
 82→      vs: vs || undefined,
 83→      difficulty,
 84→      description,
 85→      note: note || undefined,
 86→      keyTiming:
 87→        keyTimingMinute && keyTimingNote
 88→          ? { minute: keyTimingMin, note: keyTimingNote }
 89→          : undefined,
 90→      steps: steps.map((s, i) => ({
 91→        order: i + 1,
 92→        time: s.time,
 93→        instruction: s.instruction,
 94→        food: s.food,
 95→      })),
 96→      skillOrder:
 97→        skills.length > 0
 98→          ? skills.map((s) => ({
 99→              level: Number(s.level),
100→              skill: s.skill,
101→              icon: s.icon || undefined,
102→            }))
103→          : undefined,
104→    };
105→
106→    const count = importBuilds([build]);
107→    if (count > 0) {
108→      setStatus("Build order added!");
109→      setName("");
110→      setVs("");
111→      setDescription("");
112→      setNote("");
113→      setKeyTimingMinute("");
114→      setKeyTimingNote("");
115→      setSteps([{ time: "0:00", instruction: "", food: "" }]);
116→      setSkills([]);
117→    } else {
118→      setStatus("Please fill in Name and at least one step with all fields.");
119→    }
120→    setTimeout(() => setStatus(""), 4000);
121→  }
122→
123→  return (
124→    <section className="section-card build-order-input-section">
125→      <h4 className="skill-order-title">Add Build Order</h4>
126→
127→      <div className="build-order-input-fields">
128→        <div className="build-order-input-row">
129→          <span className="build-order-input-label">Name</span>
130→          <EscEditBox value={name} placeholder="Build order name" onChange={setName} />
131→        </div>
132→
133→        <div className="build-order-input-row">
134→          <span className="build-order-input-label">Race</span>
135→          <GlueDropdown
136→            options={RACES}
137→            value={race}
138→            onChange={(v) => setRace(v as Race)}
139→            label={(v) => RACE_LABELS[v as Race] ?? v}
140→          />
141→        </div>
142→
143→        <div className="build-order-input-row">
144→          <span className="build-order-input-label">vs</span>
145→          <EscEditBox value={vs} placeholder="e.g. Human, all" onChange={setVs} />
146→        </div>
147→
148→        <div className="build-order-input-row">
149→          <span className="build-order-input-label">Difficulty</span>
150→          <GlueDropdown
151→            options={DIFFICULTIES}
152→            value={difficulty}
153→            onChange={(v) => setDifficulty(v as Difficulty)}
154→          />
155→        </div>
156→
157→        <div className="build-order-input-row">
158→          <span className="build-order-input-label">Description</span>
159→          <EscEditBox value={description} placeholder="Short description" onChange={setDescription} />
160→        </div>
161→
162→        <div className="build-order-input-row">
163→          <span className="build-order-input-label">Note</span>
164→          <EscEditBox value={note} placeholder="Optional note" onChange={setNote} />
165→        </div>
166→
167→        <div className="build-order-input-row">
168→          <span className="build-order-input-label">Key Timing</span>
169→          <div className="build-order-input-key-timing">
170→            <EscEditBox value={keyTimingMinute} placeholder="Minute" onChange={setKeyTimingMinute} />
171→            <EscEditBox value={keyTimingNote} placeholder="Timing note" onChange={setKeyTimingNote} />
172→          </div>
173→        </div>
174→      </div>
175→
176→      <div className="build-order-input-steps">
177→        <h5 className="build-order-input-steps-title">Steps</h5>
178→        <table className="build-steps-table build-order-input-steps-table">
179→          <thead>
180→            <tr>
181→              <th>#</th>
182→              <th>Time</th>
183→              <th>Instruction</th>
184→              <th>Food</th>
185→              <th></th>
186→            </tr>
187→          </thead>
188→          <tbody>
189→            {steps.map((step, i) => (
190→              <tr key={i} className="build-order-input-step-row">
191→                <td className="build-step-order">{i + 1}</td>
192→                <td>
193→                  <EscEditBox
194→                    value={step.time}
195→                    placeholder="0:00"
196→                    onChange={(v) => updateStep(i, "time", v)}
197→                  />
198→                </td>
199→                <td>
200→                  <EscEditBox
201→                    value={step.instruction}
202→                    placeholder="Instruction"
203→                    onChange={(v) => updateStep(i, "instruction", v)}
204→                  />
205→                </td>
206→                <td>
207→                  <EscEditBox
208→                    value={step.food}
209→                    placeholder="5/10"
210→                    onChange={(v) => updateStep(i, "food", v)}
211→                  />
212→                </td>
213→                <td>
214→                  {steps.length > 1 && (
215→                    <GlueSmallButton onClick={() => removeStep(i)}>
216→                      ✕
217→                    </GlueSmallButton>
218→                  )}
219→                </td>
220→              </tr>
221→            ))}
222→          </tbody>
223→        </table>
224→        <div className="build-order-input-step-actions">
225→          <GlueSmallButton onClick={addStep}>+ Add Step</GlueSmallButton>
226→        </div>
227→      </div>
228→
229→      <div className="build-order-input-steps">
230→        <h5 className="build-order-input-steps-title">Skill Order</h5>
231→        <table className="build-steps-table build-order-input-steps-table">
232→          <thead>
233→            <tr>
234→              <th>Level</th>
235→              <th>Skill</th>
236→              <th>Icon Path</th>
237→              <th></th>
238→            </tr>
239→          </thead>
240→          <tbody>
241→            {skills.map((skill, i) => (
242→              <tr key={i} className="build-order-input-step-row">
243→                <td>
244→                  <EscEditBox
245→                    value={skill.level}
246→                    placeholder="1"
247→                    onChange={(v) => updateSkill(i, "level", v)}
248→                  />
249→                </td>
250→                <td>
251→                  <EscEditBox
252→                    value={skill.skill}
253→                    placeholder="Skill name"
254→                    onChange={(v) => updateSkill(i, "skill", v)}
255→                  />
256→                </td>
257→                <td>
258→                  <EscEditBox
259→                    value={skill.icon}
260→                    placeholder="/buttons/command/BTN..."
261→                    onChange={(v) => updateSkill(i, "icon", v)}
262→                  />
263→                </td>
264→                <td>
265→                  <GlueSmallButton onClick={() => removeSkill(i)}>
266→                    ✕
267→                  </GlueSmallButton>
268→                </td>
269→              </tr>
270→            ))}
271→          </tbody>
272→        </table>
273→        <div className="build-order-input-step-actions">
274→          <GlueSmallButton onClick={addSkill}>+ Add Skill</GlueSmallButton>
275→        </div>
276→      </div>
277→
278→      <div className="build-order-input-submit">
279→        <GlueBorderedButton onClick={handleSubmit}>Add Build</GlueBorderedButton>
280→      </div>
281→
282→      {status && <div className="build-import-status">{status}</div>}
283→    </section>
284→  );
285→}
