 45→function shouldForceOpaqueOnZeroAlpha(path: string): boolean {
 46→  return /\/buttons\/esc\/[^/]+\/[^/]+-options-(?:menu|button)-background(?:-down|-disabled)?\.blp$/i.test(path);
 47→}
 48→
 49→async function loadBlpDataUrl(path: string): Promise<string> {
 50→  const cached = blpDataUrlCache.get(path);
 51→  if (cached) return cached;
 52→
 53→  const promise = (async () => {
 54→    const res = await fetch(path);
 55→    if (!res.ok) throw new Error(`Failed to fetch ${path}`);
 56→    const ab = await res.arrayBuffer();
 57→    const blp = decodeBLP(ab);
 58→    const img = getBLPImageData(blp, 0);
 59→    const pixelData = new Uint8ClampedArray(img.data);
 60→
 61→    if (shouldForceOpaqueOnZeroAlpha(path)) {
 62→      let allAlphaZero = true;
 63→      for (let i = 3; i < pixelData.length; i += 4) {
 64→        if (pixelData[i] !== 0) {
 65→          allAlphaZero = false;
 66→          break;
 67→        }
 68→      }
 69→      if (allAlphaZero) {
 70→        for (let i = 3; i < pixelData.length; i += 4) {
 71→          pixelData[i] = 255;
 72→        }
 73→      }
 74→    }
 75→
 76→    const canvas = document.createElement('canvas');
 77→    canvas.width = img.width;
 78→    canvas.height = img.height;
 79→    const ctx = canvas.getContext('2d');
 80→    if (!ctx) throw new Error(`Failed to decode ${path}`);
 81→    ctx.putImageData(new ImageData(pixelData, img.width, img.height), 0, 0);
 82→    return canvas.toDataURL('image/png');
 83→  })();
 84→
 85→  blpDataUrlCache.set(path, promise);
 86→  return promise;
 87→}
 88→
 89→async function loadDataUrlImage(url: string): Promise<HTMLImageElement> {
 90→  const cached = imageCache.get(url);
 91→  if (cached) return cached;
 92→  const promise = new Promise<HTMLImageElement>((resolve, reject) => {
 93→    const img = new Image();
 94→    img.onload = () => resolve(img);
 95→    img.onerror = () => reject(new Error(`Failed to load image ${url}`));
 96→    img.src = url;
 97→  });
 98→  imageCache.set(url, promise);
 99→  return promise;
100→}
